/* ======================================================================
   Authentication
   ====================================================================== */

function bindAuth() {
  const loginForm = $('#loginForm');
  const signupForm = $('#signupForm');
  const logoutBtn = $('#logoutBtn');

  if (!loginForm) {
    console.error('Missing #loginForm in index.html');
    showAuth();
    return;
  }

  // LOGIN FORM HANDLER
  loginForm.addEventListener('submit', async (e) => {
    e.preventDefault();

    if (!supabaseClient) {
      setAuthMessage('Supabase is not loaded. Check the CDN script, config.js, and your internet connection.');
      return;
    }

    const email = $('input[name="email"]')?.value.trim() || '';
    const password = $('input[name="password"]')?.value.trim() || '';

    if (!email) {
      setAuthMessage('Please enter your email address');
      return;
    }
    if (!password) {
      setAuthMessage('Please enter your password');
      return;
    }

    const submitBtn = $('#loginSubmitBtn');
    if (submitBtn) submitBtn.disabled = true;
    setAuthMessage('Signing in...');

    try {
      const { data, error } = await supabaseClient.auth.signInWithPassword({
        email,
        password
      });

      if (error) {
        setAuthMessage('Login failed: ' + error.message);
        if (submitBtn) submitBtn.disabled = false;
        return;
      }

      setAuthMessage('');
      await afterLogin();
    } catch (err) {
      console.error(err);
      setAuthMessage('Unexpected error: ' + err.message);
      if (submitBtn) submitBtn.disabled = false;
    }
  });

  // SIGNUP FORM HANDLER
  if (signupForm) {
    signupForm.addEventListener('submit', async (e) => {
      e.preventDefault();
      if (!supabaseClient) {
        setAuthMessage('Supabase is not loaded. Check the CDN script, config.js, and your internet connection.');
        return;
      }
      const data = Object.fromEntries(new FormData(e.target).entries());
      const { error } = await supabaseClient.auth.signUp({
        email: data.email, password: data.password
      });
      setAuthMessage(error ? error.message : 'Account created. Check email confirmation if enabled.');
    });
  }

  // LOGOUT HANDLER
  if (logoutBtn) {
    logoutBtn.addEventListener('click', async () => {
      if (supabaseClient) await supabaseClient.auth.signOut();
      showAuth();
    });
  }

  // CHECK EXISTING SESSION
  if (!supabaseClient) {
    showAuth();
    setAuthMessage('Supabase is not loaded. Make sure @supabase/supabase-js loads before app.js and config.js is present.');
    return;
  }

  supabaseClient.auth.getSession().then(async ({ data }) => {
    if (data.session) await afterLogin();
    else showAuth();
  }).catch((err) => {
    console.error(err);
    showAuth();
    setAuthMessage('Could not check login session: ' + err.message);
  });
}

function setAuthMessage(msg) {
  const el = $('#authMessage');
  if (el) el.textContent = msg || '';
}

function showAuth() {
  const authScreen = $('#authScreen');
  const appRoot = $('#appRoot');
  if (authScreen) authScreen.style.display = 'flex';
  if (appRoot) appRoot.style.display = 'none';
}

function showApp() {
  const authScreen = $('#authScreen');
  const appRoot = $('#appRoot');
  if (authScreen) authScreen.style.display = 'none';
  if (appRoot) appRoot.style.display = 'grid';
}

async function afterLogin() {
  showApp();
  await loadAllData();
  await resolveCurrentUser();
  applyRoleUI();
  renderAll();
}

/* ======================================================================
   Role / access control
   ====================================================================== */

// Populated after login. Shape:
//   { email, isAdmin: bool, unit: 'Boyscouts'|null, leader: {...}|null }
const currentUser = { email: null, isAdmin: false, unit: null, leader: null };

/**
 * Try to derive the scout unit from an email address.
 * Recognizes patterns like:
 *   saida01.boyscouts@lsa.org.lb   -> "Boyscouts"
 *   saida01.cubscouts@lsa.org.lb   -> "Cubs"
 *   saida01.girlscouts@lsa.org.lb  -> "Girlscouts"
 *   boyscouts@anything             -> "Boyscouts"
 */
function unitFromEmail(email) {
  if (!email) return null;
  const local = String(email).toLowerCase().split('@')[0] || '';
  // 1) Direct token after a dot/underscore/dash: "saida01.boyscouts" -> "boyscouts"
  const tokens = local.split(/[.\-_+]/).filter(Boolean);
  for (const t of tokens) {
    const u = canonicalUnit(t);
    if (u) return u;
  }
  // 2) Substring scan (handles e.g. "boyscoutsleader")
  const compact = local.replace(/[\s_\-.+]+/g, '');
  const keywords = [
    'cubscouts','girlscouts','boyscouts','beavers','pioneers','rovers',
    'cubs','girls','scouts','beaver','cub','girlscout','boyscout','pioneer','rover'
  ];
  for (const kw of keywords) {
    if (compact.includes(kw)) return canonicalUnit(kw);
  }
  return null;
}

async function resolveCurrentUser() {
  currentUser.email = null;
  currentUser.isAdmin = false;
  currentUser.unit = null;
  currentUser.leader = null;

  if (!supabaseClient) return;

  let user = null;
  try {
    const { data } = await supabaseClient.auth.getUser();
    user = data?.user || null;
  } catch (_) {}
  if (!user) return;

  const email = (user.email || '').trim().toLowerCase();
  currentUser.email = email;

  // ---- Role lookup: prefer Supabase auth metadata, fall back to email pattern ----
  // Prefer app_metadata (only editable server-side => more secure);
  // fall back to user_metadata for convenience.
  const appMeta  = user.app_metadata  || {};
  const userMeta = user.user_metadata || {};
  const rawRole = String(appMeta.role || userMeta.role || '').trim().toLowerCase();
  const rawUnit = String(appMeta.unit || userMeta.unit || '').trim();

  if (rawRole === 'admin' || rawRole === 'administrator' || rawRole.includes('admin')) {
    currentUser.isAdmin = true;
  } else {
    // Try, in order: role metadata -> explicit unit metadata -> email pattern.
    let unit = null;

    if (rawRole) {
      unit = canonicalUnit(rawRole);
      if (!unit) {
        const compact = rawRole.replace(/[\s_\-]+/g, '');
        const keywords = ['cubscouts','girlscouts','boyscouts','beavers','pioneers','rovers','cubs','girls','scouts','beaver','cub','girlscout','boyscout','pioneer','rover'];
        for (const kw of keywords) {
          if (compact.includes(kw)) { unit = canonicalUnit(kw); break; }
        }
      }
    }
    if (!unit && rawUnit) unit = canonicalUnit(rawUnit);
    if (!unit)            unit = unitFromEmail(email);

    currentUser.unit = unit || null;
  }

  // Optionally attach the matching leader row (for profile display only,
  // not for access control).
  // Strict match — never fall back to a random leader row when either
  // side is empty. Both the auth email AND the leader row's email must
  // be non-empty and identical (case-insensitive).
  currentUser.leader = (email
    ? (state.leaders || []).find(l => {
        const le = (l && l.email ? String(l.email) : '').trim().toLowerCase();
        return le && le === email;
      })
    : null) || null;
}

function scopedMembers() {
  if (!currentUser.isAdmin && currentUser.unit) {
    return (state.members || []).filter(m => canonicalUnit(m.unit) === currentUser.unit);
  }
  return state.members || [];
}

/** Views a non-admin unit leader is allowed to see. */
const UNIT_LEADER_VIEWS = new Set(['dashboard', 'units', 'configuration', 'memberProfile', 'leaderProfile']);
/** Config tabs a non-admin unit leader is allowed to see. */
const UNIT_LEADER_CONFIG_TABS = new Set(['assign-badges-tab']);

function applyRoleUI() {
  const isAdmin = currentUser.isAdmin;
  const hasUnit = !!currentUser.unit;

  // ---- Sidebar menu items ----
  document.querySelectorAll('.menu-item[data-view]').forEach(btn => {
    const view = btn.dataset.view;
    const allowed = isAdmin || UNIT_LEADER_VIEWS.has(view);
    btn.style.display = allowed ? '' : 'none';
  });

  // ---- Config tabs ----
  document.querySelectorAll('.config-tab-btn[data-config-tab]').forEach(btn => {
    const tab = btn.dataset.configTab;
    const allowed = isAdmin || UNIT_LEADER_CONFIG_TABS.has(tab);
    btn.style.display = allowed ? '' : 'none';
  });
  if (!isAdmin) {
    // If the active config tab is now hidden, activate the first visible one.
    const activeBtn = document.querySelector('.config-tab-btn.active');
    if (activeBtn && activeBtn.style.display === 'none') {
      const firstVisible = document.querySelector('.config-tab-btn:not([style*="display: none"])');
      if (firstVisible) firstVisible.click();
    }
  }

  // ---- Role badge in the header (optional; only added if a slot exists) ----
  const badgeSlot = document.getElementById('roleBadge');
  if (badgeSlot) {
    if (isAdmin) badgeSlot.textContent = 'Admin';
    else if (currentUser.unit) badgeSlot.textContent = `${currentUser.unit} Leader`;
    else badgeSlot.textContent = '';
  }

  // ---- If user has no scope, force dashboard so they see the empty state ----
  if (!isAdmin && !hasUnit) {
    switchView('dashboard');
  } else if (!isAdmin) {
    // If user landed on a hidden view (from a prior admin session), reset to dashboard.
    const activeView = document.querySelector('.view.active');
    if (activeView && !UNIT_LEADER_VIEWS.has(activeView.id)) {
      switchView('dashboard');
    }
  }
}

/** Renders a "no unit assigned" empty state over the dashboard. */
function renderNoUnitDashboard() {
  const containers = [
    '#statsGrid', '#upcomingTransitions', '#recentMeetings'
  ];
  containers.forEach(sel => { const el = $(sel); if (el) el.innerHTML = ''; });
  const cardsRow = document.querySelector('.stats-cards-row');
  const chartsGrid = document.querySelector('.stats-charts-grid');
  if (cardsRow) cardsRow.style.display = 'none';
  if (chartsGrid) chartsGrid.style.display = 'none';

  const dash = document.getElementById('dashboard');
  if (!dash) return;
  if (!dash.querySelector('#noUnitEmpty')) {
    const empty = document.createElement('div');
    empty.id = 'noUnitEmpty';
    empty.className = 'panel';
    empty.style.cssText = 'text-align:center; padding:48px 24px;';
    empty.innerHTML = `
      <div style="font-size:44px; margin-bottom:12px;">🔒</div>
      <h2 style="margin:0 0 8px;">No role assigned</h2>
      <p class="muted" style="max-width:520px; margin:0 auto;">
        Your account (${escapeHtml(currentUser.email || '')}) doesn't have a role set yet.
        Ask an admin to either set your <code>role</code> in Supabase Authentication
        (e.g. <code>admin</code>, <code>boyscouts</code>, <code>cubs</code>, <code>rovers</code>),
        or use a unit-based email such as <code>saida01.boyscouts@lsa.org.lb</code>.
      </p>
    `;
    dash.appendChild(empty);
  }
}
function clearNoUnitDashboard() {
  const empty = document.getElementById('noUnitEmpty');
  if (empty) empty.remove();
  const cardsRow = document.querySelector('.stats-cards-row');
  const chartsGrid = document.querySelector('.stats-charts-grid');
  if (cardsRow) cardsRow.style.display = '';
  if (chartsGrid) chartsGrid.style.display = '';
}

/* ======================================================================
   Boot
   ====================================================================== */

function init() {
  bindAuth();
  bindMenu();
  bindForms();

  // Bind Desktop Global Refresh Button (Bypasses cache and updates UI aggregates)
  const desktopRefreshBtn = $('#desktopRefreshBtn');
  if (desktopRefreshBtn) {
    desktopRefreshBtn.addEventListener('click', async () => {
      const svg = desktopRefreshBtn.querySelector('svg');
      if (svg) svg.style.transform = 'rotate(360deg)';
      desktopRefreshBtn.disabled = true;
      desktopRefreshBtn.textContent = 'Refreshing...';
      try {
        await loadAllData();
        renderAll();
        showToast('Data successfully refreshed from Supabase', 'success');
      } catch (err) {
        showToast('Refresh failed: ' + err.message, 'error');
      } finally {
        desktopRefreshBtn.disabled = false;
        desktopRefreshBtn.innerHTML = `
          <svg width="16" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" style="transition: transform 0.3s ease;"><path d="M21.5 2v6h-6M21.34 15.57a10 10 0 1 1-.57-8.38l5.67-5.67"/></svg>
          Refresh Data
        `;
      }
    });
  }

  bindMeetingBuilderButtons();
  bindConfigTabs();
  bindMemberImportExport();
  bindLeaderImportExport();
  bindBadgeDefImportExport();
  bindMobileSidebar();

  const backBtn = $('#backToUnitsBtn');
  if (backBtn) {
    backBtn.addEventListener('click', () => {
      switchView('units');
      renderUnitsPage();
    });
  }

  const dlProfileBtn = $('#downloadProfilePdfBtn');
  if (dlProfileBtn) {
    dlProfileBtn.addEventListener('click', () => {
      const mid = dlProfileBtn.dataset.memberId;
      if (mid) downloadMemberProfilePdf(mid);
    });
  }

  bindAssignBadgesControls();
  const applyBtn = $('#applyBadgesBtn');
  if (applyBtn) {
    applyBtn.addEventListener('click', handleApplyBadges);
  }

  const backToUnitsFromLeaderBtn = $('#backToUnitsFromLeaderBtn');
  if (backToUnitsFromLeaderBtn) {
    backToUnitsFromLeaderBtn.addEventListener('click', () => {
      switchView('units');
      renderUnitsPage();
    });
  }

  const dlLeaderPdfBtn = $('#downloadLeaderPdfBtn');
  if (dlLeaderPdfBtn) {
    dlLeaderPdfBtn.addEventListener('click', () => {
      const lid = dlLeaderPdfBtn.dataset.leaderId;
      if (lid) downloadLeaderProfilePdf(lid);
    });
  }
}

function bindMenu() {
  document.querySelectorAll('.menu-item').forEach(btn => {
    btn.addEventListener('click', () => {
      document.querySelectorAll('.menu-item').forEach(b => b.classList.remove('active'));
      document.querySelectorAll('.view').forEach(v => v.classList.remove('active'));
      btn.classList.add('active');
      document.getElementById(btn.dataset.view).classList.add('active');
      if (btn.dataset.view === 'meetings') renderMeetings();
      if (btn.dataset.view === 'dashboard') renderStatisticsPage();
      if (btn.dataset.view === 'units') renderUnitsPage();
    });
  });
}

function bindConfigTabs() {
  document.querySelectorAll('.config-tab-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      document.querySelectorAll('.config-tab-btn').forEach(b => b.classList.remove('active'));
      document.querySelectorAll('.config-tab-panel').forEach(p => p.classList.remove('active'));
      btn.classList.add('active');
      const panel = document.getElementById(btn.dataset.configTab);
      if (panel) panel.classList.add('active');

      if (btn.dataset.configTab === 'badges-def-tab') {
        renderBadgeDefs();
      }

      if (btn.dataset.configTab === 'assign-badges-tab') {
        selectedPersonId = null;
        selectedPersonType = null;
        assignBadgesActiveFilter = (!currentUser.isAdmin && currentUser.unit)
          ? currentUser.unit
          : 'All';
        assignBadgesSearchQuery = '';
        const searchInput = $('#assignBadgesSearchInput');
        if (searchInput) searchInput.value = '';
        document.querySelectorAll('#assignBadgesUnitFilters .filter-pill').forEach(b => b.classList.remove('active'));
        const activePillSel = `#assignBadgesUnitFilters .filter-pill[data-unit="${assignBadgesActiveFilter}"]`;
        const activePill = document.querySelector(activePillSel);
        if (activePill) activePill.classList.add('active');
        renderAssignBadgesPeopleList();
        const container = $('#assignBadgesListContainer');
        if (container) container.style.display = 'none';
      }
    });
  });
}

function switchView(id) {
  // Block non-admins from navigating to hidden views.
  if (currentUser && currentUser.email && !currentUser.isAdmin && !UNIT_LEADER_VIEWS.has(id)) {
    id = 'dashboard';
  }
  document.querySelectorAll('.menu-item').forEach(b => b.classList.toggle('active', b.dataset.view === id));
  document.querySelectorAll('.view').forEach(v => v.classList.toggle('active', v.id === id));
}

function formToObject(form) {
  return Object.fromEntries(new FormData(form).entries());
}

/* ======================================================================
   Forms (CRUD)
   ====================================================================== */

function bindForms() {
  const meetingForm = $('#meetingForm');
  if (meetingForm) meetingForm.addEventListener('submit', handleMeetingSubmit);

  const memberForm = $('#memberForm');
  if (memberForm) {
    memberForm.addEventListener('submit', async e => {
      e.preventDefault();
      const d = formToObject(e.target);
      const parts = [d.firstName, d.middleName, d.lastName].filter(Boolean);
      const { data, error } = await supabaseClient.from('members').insert({
        first_name: d.firstName,
        middle_name: d.middleName || null,
        last_name: d.lastName,
        full_name: parts.join(' '),
        unit: d.unit,
        gender: d.gender || null,
        phone: d.phone || null,
        parent_type: d.parentType || null,
        parent_phone: d.parentPhone || null,
        blood_type: d.bloodType || null,
        nationality: d.nationality || null,
        dob: d.dob,
        email: d.email || null
      }).select().single();
      if (error) return showToast(error.message, 'error');
      state.members.push(mapMember(data));
      showToast('Member added successfully', 'success');
      e.target.reset();
      renderAll();
    });
  }

  const leaderForm = $('#leaderForm');
  if (leaderForm) {
    leaderForm.addEventListener('submit', async e => {
      e.preventDefault();
      const d = formToObject(e.target);
      const parts = [d.firstName, d.middleName, d.lastName].filter(Boolean);
      const { data, error } = await supabaseClient.from('leaders').insert({
        first_name: d.firstName,
        middle_name: d.middleName || null,
        last_name: d.lastName,
        full_name: parts.join(' '),
        gender: d.gender || null,
        role: d.role,
        phone: d.phone || null,
        parent_phone: d.parentPhone || null,
        blood_type: d.bloodType || null,
        nationality: d.nationality || null,
        dob: d.dob || null,
        email: d.email || null
      }).select().single();
      if (error) return showToast(error.message, 'error');
      state.leaders.push(mapLeader(data));
      showToast('Leader added successfully', 'success');
      e.target.reset();
      renderAll();
      renderMeetingLeaderRows();
    });
  }

  const paymentForm = $('#paymentForm');
  if (paymentForm) {
    paymentForm.addEventListener('submit', async e => {
      e.preventDefault();
      const d = formToObject(e.target);
      const { data, error } = await supabaseClient.from('payments').insert({
        member_id: d.memberId, year: Number(d.year), amount: Number(d.amount),
        status: d.status, payment_date: d.paymentDate || null, notes: d.notes
      }).select().single();
      if (error) return showToast(error.message, 'error');
      state.payments.push(mapPayment(data));
      showToast('Payment recorded', 'success');
      e.target.reset();
      renderAll();
    });
  }

  const badgeForm = $('#badgeForm');
  if (badgeForm) {
    badgeForm.addEventListener('submit', async e => {
      e.preventDefault();
      const d = formToObject(e.target);
      const { data, error } = await supabaseClient.from('badges').insert({
        member_id: d.memberId, badge_name: d.badgeName,
        awarded_date: d.awardedDate, awarded_by: d.awardedBy
      }).select().single();
      if (error) return showToast(error.message, 'error');
      state.badges.push(mapBadge(data));
      showToast('Badge awarded!', 'success');
      e.target.reset();
      renderAll();
    });
  }

  const rankForm = $('#rankForm');
  if (rankForm) {
    rankForm.addEventListener('submit', async e => {
      e.preventDefault();
      const d = formToObject(e.target);
      const { data, error } = await supabaseClient.from('ranks').insert({
        member_id: d.memberId, rank_name: d.rankName,
        effective_date: d.effectiveDate, notes: d.notes
      }).select().single();
      if (error) return showToast(error.message, 'error');
      state.ranks.push(mapRank(data));
      showToast('Rank updated', 'success');
      e.target.reset();
      renderAll();
    });
  }

  const memberAttendanceForm = $('#memberAttendanceForm');
  if (memberAttendanceForm) {
    memberAttendanceForm.addEventListener('submit', async e => {
      e.preventDefault();
      const d = formToObject(e.target);
      const { data, error } = await supabaseClient.from('member_attendance').insert({
        member_id: d.memberId, date: d.date, status: d.status,
        activity: d.activity, notes: d.notes
      }).select().single();
      if (error) return showToast(error.message, 'error');
      state.memberAttendance.push(mapMemberAttendance(data));
      showToast('Member attendance saved', 'success');
      e.target.reset();
      renderAll();
    });
  }

  const leaderAttendanceForm = $('#leaderAttendanceForm');
  if (leaderAttendanceForm) {
    leaderAttendanceForm.addEventListener('submit', async e => {
      e.preventDefault();
      const d = formToObject(e.target);
      const { data, error } = await supabaseClient.from('leader_attendance').insert({
        leader_id: d.leaderId, date: d.date, status: d.status,
        meeting: d.meeting, notes: d.notes
      }).select().single();
      if (error) return showToast(error.message, 'error');
      state.leaderAttendance.push(mapLeaderAttendance(data));
      showToast('Leader attendance saved', 'success');
      e.target.reset();
      renderAll();
    });
  }

  const badgeDefForm = $('#badgeDefForm');
  if (badgeDefForm) {
    badgeDefForm.addEventListener('submit', handleBadgeDefSubmit);

    const logoFile = $('#badgeLogoFile');
    const logoUrlInput = badgeDefForm.querySelector('[name="logoUrl"]');
    const preview = $('#badgeLogoPreview');

    const updatePreview = (url) => {
      if (!preview) return;
      preview.innerHTML = url
        ? `<img src="${escapeHtml(url)}" style="max-height:62px; max-width:110px; border-radius:8px; border:1px solid rgba(255,255,255,0.1);" />`
        : '';
    };

    if (logoFile) {
      logoFile.addEventListener('change', async (e) => {
        const file = e.target.files?.[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = (ev) => {
          updatePreview(ev.target.result);
          logoFile.dataset.previewData = ev.target.result;
        };
        reader.readAsDataURL(file);
      });
    }

    if (logoUrlInput) {
      logoUrlInput.addEventListener('input', () => {
        if (logoUrlInput.value.trim()) updatePreview(logoUrlInput.value.trim());
      });
    }
  }
}

