/* ======================================================================
   Unit transition rules
   ====================================================================== */

const UNIT_TRANSITIONS = {
  Beavers: { nextAge: 7, next: 'Cubs' },
  Cubs: { nextAge: 11, next: 'Boyscouts/Girlscouts' },
  Boyscouts: { nextAge: 16, next: 'Rovers' },
  Girlscouts: { nextAge: 16, next: 'Pioneers' },
  Pioneers: { nextAge: 18, next: 'Leaders' },
  Rovers: { nextAge: 18, next: 'Leaders' }
};
const TRANSITION_WINDOW_DAYS = 180;

/** How far ahead (in days) to look for incoming/outgoing members on the
 *  unit-leader dashboard. */
const LEADER_WINDOW_DAYS = 150;

/** Which unit(s) feed into a given target unit, and the gender filter
 *  (if any) that must be applied to the source unit's members. */
const INCOMING_SOURCES = {
  Cubs:       [{ from: 'Beavers',    gender: null   }],
  Boyscouts:  [{ from: 'Cubs',       gender: 'male' }],
  Girlscouts: [{ from: 'Cubs',       gender: 'female' }],
  Rovers:     [{ from: 'Boyscouts',  gender: null   }],
  Pioneers:   [{ from: 'Girlscouts', gender: null   }]
  // Beavers has no feeder unit; Leaders is a terminal role.
};

function canonicalUnit(raw) {
  if (!raw) return null;
  const s = String(raw).toLowerCase().replace(/[\s_\-]+/g, '');
  const map = {
    beavers: 'Beavers', beaver: 'Beavers',
    cubs: 'Cubs', cub: 'Cubs', cubscouts: 'Cubs', cubscout: 'Cubs',
    boyscouts: 'Boyscouts', boyscout: 'Boyscouts', scouts: 'Boyscouts',
    girlscouts: 'Girlscouts', girlscout: 'Girlscouts', girls: 'Girlscouts',
    pioneers: 'Pioneers', pioneer: 'Pioneers',
    rovers: 'Rovers', rover: 'Rovers'
  };
  return map[s] || null;
}

function nextUnitFor(unit, member) {
  const u = canonicalUnit(unit);
  if (u !== 'Cubs') return UNIT_TRANSITIONS[u]?.next;
  const g = String(member?.gender || '').toLowerCase();
  if (g === 'male' || g === 'm') return 'Boyscouts';
  if (g === 'female' || g === 'f') return 'Girlscouts';
  return 'Boyscouts/Girlscouts';
}

function ageDecimal(dob) {
  if (!dob) return null;
  const birth = new Date(dob);
  if (isNaN(birth)) return null;
  const ms = new Date() - birth;
  if (ms < 0) return null;
  return Math.round((ms / (1000 * 60 * 60 * 24 * 365.2425)) * 100) / 100;
}

function timeUntilNextUnit(member) {
  if (!member?.dob || !member?.unit) return null;
  const unit = canonicalUnit(member.unit);
  if (!unit) return null;
  const rule = UNIT_TRANSITIONS[unit];
  if (!rule) return null;

  const birth = new Date(member.dob);
  if (isNaN(birth)) return null;
  const boundary = new Date(birth);
  boundary.setFullYear(birth.getFullYear() + rule.nextAge);

  const today = new Date(); today.setHours(0, 0, 0, 0);
  boundary.setHours(0, 0, 0, 0);

  if (boundary <= today) {
    return {
      passed: true, text: 'eligible to move now', days: 0,
      boundaryDate: boundary, nextUnit: nextUnitFor(unit, member)
    };
  }

  let y = boundary.getFullYear() - today.getFullYear();
  let m = boundary.getMonth() - today.getMonth();
  let d = boundary.getDate() - today.getDate();
  if (d < 0) {
    m -= 1;
    const prev = new Date(boundary.getFullYear(), boundary.getMonth(), 0);
    d += prev.getDate();
  }
  if (m < 0) { y -= 1; m += 12; }

  const parts = [];
  if (y) parts.push(`${y} year${y === 1 ? '' : 's'}`);
  if (m) parts.push(`${m} month${m === 1 ? '' : 's'}`);
  if (d || (!y && !m)) parts.push(`${d} day${d === 1 ? '' : 's'}`);

  const totalDays = Math.round((boundary - today) / (1000 * 60 * 60 * 24));
  return {
    passed: false, text: parts.join(', '), days: totalDays,
    boundaryDate: boundary, nextUnit: nextUnitFor(unit, member)
  };
}

function computeUpcomingTransitions() {
  const today = new Date(); today.setHours(0, 0, 0, 0);
  const results = [];

  scopedMembers().forEach(m => {
    if (!m.dob || !m.unit) return;
    const unit = canonicalUnit(m.unit);
    const rule = unit ? UNIT_TRANSITIONS[unit] : null;
    if (!rule) return;

    const birth = new Date(m.dob);
    if (isNaN(birth)) return;
    const boundary = new Date(birth);
    boundary.setFullYear(birth.getFullYear() + rule.nextAge);
    boundary.setHours(0, 0, 0, 0);

    const daysLeft = Math.round((boundary - today) / (1000 * 60 * 60 * 24));
    if (daysLeft <= TRANSITION_WINDOW_DAYS) {
      results.push({
        member: m, currentUnit: unit, nextUnit: nextUnitFor(unit, m),
        daysLeft, boundaryDate: boundary
      });
    }
  });

  results.sort((a, b) => a.daysLeft - b.daysLeft);
  return results;
}

/**
 * For a unit leader's dashboard: computes the members from OTHER units who
 * will age into this unit within `windowDays`, and the members from THIS unit
 * who will move out to the next unit within `windowDays`.
 * Returns `{ incoming, outgoing }` where each is a sorted array of items:
 *   { member, currentUnit, nextUnit, daysLeft, boundaryDate }
 * `daysLeft < 0` means already overdue.
 */
function computeUnitFlow(targetUnit, windowDays = LEADER_WINDOW_DAYS) {
  const today = new Date(); today.setHours(0, 0, 0, 0);
  const incoming = [];
  const outgoing = [];
  if (!targetUnit) return { incoming, outgoing };

  const members = state.members || [];

  // --- Outgoing: members currently in this unit moving to their next unit ---
  const outRule = UNIT_TRANSITIONS[targetUnit];
  if (outRule) {
    members.forEach(m => {
      if (canonicalUnit(m.unit) !== targetUnit) return;
      if (!m.dob) return;
      const birth = new Date(m.dob);
      if (isNaN(birth)) return;
      const boundary = new Date(birth);
      boundary.setFullYear(birth.getFullYear() + outRule.nextAge);
      boundary.setHours(0, 0, 0, 0);
      const daysLeft = Math.round((boundary - today) / (1000 * 60 * 60 * 24));
      if (daysLeft <= windowDays) {
        outgoing.push({
          member: m,
          currentUnit: targetUnit,
          nextUnit: nextUnitFor(targetUnit, m),
          daysLeft,
          boundaryDate: boundary
        });
      }
    });
  }

  // --- Incoming: members in feeder unit(s) aging into this unit ---
  const sources = INCOMING_SOURCES[targetUnit] || [];
  sources.forEach(src => {
    const srcRule = UNIT_TRANSITIONS[src.from];
    if (!srcRule) return;
    members.forEach(m => {
      if (canonicalUnit(m.unit) !== src.from) return;
      // Apply gender filter for cubs-splits
      if (src.gender) {
        const g = String(m.gender || '').toLowerCase();
        const wantMale   = src.gender === 'male'   && (g === 'male'   || g === 'm');
        const wantFemale = src.gender === 'female' && (g === 'female' || g === 'f');
        if (!wantMale && !wantFemale) return;
      }
      if (!m.dob) return;
      const birth = new Date(m.dob);
      if (isNaN(birth)) return;
      const boundary = new Date(birth);
      boundary.setFullYear(birth.getFullYear() + srcRule.nextAge);
      boundary.setHours(0, 0, 0, 0);
      const daysLeft = Math.round((boundary - today) / (1000 * 60 * 60 * 24));
      if (daysLeft <= windowDays) {
        incoming.push({
          member: m,
          currentUnit: src.from,
          nextUnit: targetUnit,
          daysLeft,
          boundaryDate: boundary
        });
      }
    });
  });

  incoming.sort((a, b) => a.daysLeft - b.daysLeft);
  outgoing.sort((a, b) => a.daysLeft - b.daysLeft);
  return { incoming, outgoing };
}

function renderUnitFlowPanel() {
  // Admin doesn't need this panel — the general upcoming-transitions
  // panel above already covers everything.
  if (currentUser.isAdmin || !currentUser.unit) {
    const existing = document.getElementById('unitFlowPanel');
    if (existing) existing.style.display = 'none';
    return;
  }

  // Try to find the pre-declared slot in index.html. If it's missing (e.g.
  // an older index.html hasn't been redeployed), inject one into the
  // dashboard section so the feature still works.
  let container = document.getElementById('unitFlowPanel');
  if (!container) {
    const dash = document.getElementById('dashboard');
    if (!dash) return;
    container = document.createElement('div');
    container.id = 'unitFlowPanel';
    container.className = 'unit-flow-panel';
    container.style.marginBottom = '20px';

    // Insert right after the "Upcoming Unit Transitions" panel if we can find
    // it, otherwise before the charts grid, otherwise at the end.
    const anchor =
      document.getElementById('upcomingTransitions')?.closest('.panel') ||
      dash.querySelector('.stats-charts-grid');
    if (anchor && anchor.parentNode === dash) {
      dash.insertBefore(container, anchor.nextSibling);
    } else if (anchor) {
      anchor.parentNode.insertBefore(container, anchor);
    } else {
      dash.appendChild(container);
    }
  }
  container.style.display = 'grid';

  const unit = currentUser.unit;
  const { incoming, outgoing } = computeUnitFlow(unit, LEADER_WINDOW_DAYS);

  const renderRow = (item, mode) => {
    const overdue = item.daysLeft < 0;
    let dayLabel;
    if (item.daysLeft === 0) dayLabel = 'Today';
    else if (overdue) dayLabel = `${Math.abs(item.daysLeft)} day${Math.abs(item.daysLeft) === 1 ? '' : 's'} overdue`;
    else dayLabel = `${item.daysLeft} day${item.daysLeft === 1 ? '' : 's'} left`;

    const dateLabel = escapeHtml(formatLongDate(item.boundaryDate.toISOString().slice(0, 10)));
    const arrow = mode === 'incoming'
      ? `${escapeHtml(item.currentUnit)} → <strong>${escapeHtml(item.nextUnit)}</strong>`
      : `<strong>${escapeHtml(item.currentUnit)}</strong> → ${escapeHtml(item.nextUnit)}`;
    const urgencyClass = overdue ? 'overdue' : (item.daysLeft <= 30 ? 'soon' : '');
    const verb = mode === 'incoming'
      ? (overdue ? 'should have joined' : 'joins')
      : (overdue ? 'should have moved out' : 'moves out');

    return `
      <div class="transition-row ${urgencyClass}">
        <div class="transition-name">
          <strong>${escapeHtml(item.member.fullName || '')}</strong>
          <span class="transition-meta">${arrow}</span>
        </div>
        <div class="transition-detail">
          <span class="transition-days">${dayLabel}</span>
          <span class="transition-sub">${verb} on ${dateLabel}</span>
        </div>
      </div>
    `;
  };

  const incHtml = incoming.length
    ? incoming.map(i => renderRow(i, 'incoming')).join('')
    : `<div class="empty" style="padding:14px; text-align:center;">No incoming members in the next ${LEADER_WINDOW_DAYS} days.</div>`;
  const outHtml = outgoing.length
    ? outgoing.map(i => renderRow(i, 'outgoing')).join('')
    : `<div class="empty" style="padding:14px; text-align:center;">No ${escapeHtml(unit)} members moving out in the next ${LEADER_WINDOW_DAYS} days.</div>`;

  // Inline styles so this works even without the styles.css update.
  container.style.display = 'grid';
  container.style.gap = '20px';
  container.style.gridTemplateColumns = window.matchMedia('(max-width: 900px)').matches
    ? '1fr' : 'repeat(2, 1fr)';

  container.innerHTML = `
    <div class="panel" style="margin-bottom:0;">
      <div class="panel-header">
        <h3>⬅ Incoming to ${escapeHtml(unit)}</h3>
        <span class="muted" style="font-size:13px;">Next ${LEADER_WINDOW_DAYS} days · ${incoming.length} member${incoming.length === 1 ? '' : 's'}</span>
      </div>
      <div class="transitions-list">${incHtml}</div>
    </div>
    <div class="panel" style="margin-bottom:0;">
      <div class="panel-header">
        <h3>➡ Outgoing from ${escapeHtml(unit)}</h3>
        <span class="muted" style="font-size:13px;">Next ${LEADER_WINDOW_DAYS} days · ${outgoing.length} member${outgoing.length === 1 ? '' : 's'}</span>
      </div>
      <div class="transitions-list">${outHtml}</div>
    </div>
  `;
}

function renderUpcomingTransitions() {
  const container = $('#upcomingTransitions');
  if (!container) return;

  const items = computeUpcomingTransitions();
  if (!items.length) {
    container.innerHTML = '<div class="empty">No members are eligible to move or within 6 months of moving to another unit.</div>';
    return;
  }

  container.innerHTML = items.map(item => {
    const overdue = item.daysLeft < 0;
    const overdueDays = Math.abs(item.daysLeft);

    const urgencyClass =
      overdue ? 'urgency-overdue' :
        item.daysLeft <= 30 ? 'urgency-critical' :
          item.daysLeft <= 90 ? 'urgency-warning' : 'urgency-info';

    let dayLabel;
    if (overdue) dayLabel = `Eligible now — ${overdueDays} day${overdueDays === 1 ? '' : 's'} overdue`;
    else if (item.daysLeft === 0) dayLabel = 'Eligible today';
    else dayLabel = `${item.daysLeft} day${item.daysLeft === 1 ? '' : 's'} left`;

    const verb = overdue ? 'should have moved from' : 'to move from';
    const tail = `${escapeHtml(item.currentUnit)} to ${escapeHtml(item.nextUnit)}`;
    const dateLabel = escapeHtml(formatLongDate(item.boundaryDate.toISOString().slice(0, 10)));

    return `
      <div class="transition-row ${urgencyClass}">
        <div class="transition-name">
          <strong>${escapeHtml(item.member.fullName)}</strong>
          <span class="transition-meta">${escapeHtml(item.currentUnit)} → ${escapeHtml(item.nextUnit)}</span>
        </div>
        <div class="transition-detail">
          <span class="transition-days">${dayLabel}</span>
          <span class="transition-sub">${verb} ${tail} on ${dateLabel}</span>
        </div>
      </div>
    `;
  }).join('');
}

/* ======================================================================
   Dashboard stats
   ====================================================================== */

function renderStats() {
  // Scope for non-admins: only their unit's members.
  if (!currentUser.isAdmin && !currentUser.unit) {
    renderNoUnitDashboard();
    return;
  }
  clearNoUnitDashboard();

  const members = scopedMembers();
  const memberIds = new Set(members.map(m => m.id));
  const payments = (state.payments || []).filter(p => memberIds.has(p.memberId));

  const unpaid = members.length - new Set(
    payments.filter(p => p.status === 'Paid').map(p => p.memberId)
  ).size;

  const leadersCount = currentUser.isAdmin
    ? (state.leaders || []).length
    : (currentUser.leader ? 1 : 0);

  const statsGrid = $('#statsGrid');
  if (statsGrid) {
    const membersTitle = currentUser.isAdmin ? 'Total Members' : `${currentUser.unit} Members`;
    const cards = [
      statCard(membersTitle, members.length, ''),
      currentUser.isAdmin ? statCard('Total Leaders', leadersCount, '') : null,
      statCard('Paid this Year',
        payments.filter(p => p.status === 'Paid').length,
        `${unpaid < 0 ? 0 : unpaid} unpaid`)
    ].filter(Boolean);
    statsGrid.innerHTML = cards.join('');
  }

  const memberPresent = state.memberAttendance.filter(a => a.status === 'Present').length;
  const leaderPresent = state.leaderAttendance.filter(a => a.status === 'Present').length;
  const memberTotal = Math.max(state.memberAttendance.length, 1);
  const leaderTotal = Math.max(state.leaderAttendance.length, 1);

  const memberPresentBar = $('#memberPresentBar');
  if (memberPresentBar) memberPresentBar.style.width = `${(memberPresent / memberTotal) * 100}%`;
  const leaderPresentBar = $('#leaderPresentBar');
  if (leaderPresentBar) leaderPresentBar.style.width = `${(leaderPresent / leaderTotal) * 100}%`;
  const memberPresentText = $('#memberPresentText');
  if (memberPresentText) memberPresentText.textContent = `${memberPresent}/${state.memberAttendance.length}`;
  const leaderPresentText = $('#leaderPresentText');
  if (leaderPresentText) leaderPresentText.textContent = `${leaderPresent}/${state.leaderAttendance.length}`;

  const recentMeetings = $('#recentMeetings');
  if (recentMeetings) {
    recentMeetings.innerHTML = state.meetings.length
      ? state.meetings.slice(0, 5).map(meetingCard).join('')
      : '<div class="empty">No meetings yet.</div>';

    document.querySelectorAll('.meeting-card').forEach(card => {
      card.addEventListener('click', () => {
        switchView('meetings');
        openMeetingRecordView(card.dataset.id);
      });
    });
  }

  // Admins see the general "upcoming transitions" panel; unit leaders see
  // the incoming/outgoing panel instead.
  const upcomingContainer = $('#upcomingTransitions')?.closest('.panel');
  if (upcomingContainer) {
    upcomingContainer.style.display = currentUser.isAdmin ? '' : 'none';
  }
  if (currentUser.isAdmin) renderUpcomingTransitions();
  renderUnitFlowPanel();
}

function statCard(title, value, sub) {
  return `<div class="stat-card"><div class="stat-title">${title}</div><div class="stat-value">${value}</div><div class="stat-sub">${sub}</div></div>`;
}

