function enhanceBadgeAwardForm() {
  const form = $('#badgeForm');
  if (!form) return;

  let nameField = form.querySelector('input[name="badgeName"]');
  if (!nameField) return;

  if (nameField.tagName === 'SELECT') return;

  const hasDefs = state.badgeDefs.length > 0;

  if (hasDefs) {
    const select = document.createElement('select');
    select.name = 'badgeName';
    select.required = true;

    select.innerHTML = '<option value="">Select Badge</option>' +
      state.badgeDefs.map(b => `<option value="${escapeHtml(b.name)}">${escapeHtml(b.name)}</option>`).join('');

    const customOpt = document.createElement('option');
    customOpt.value = '__custom__';
    customOpt.textContent = '— Other (type custom) —';
    select.appendChild(customOpt);

    nameField.parentNode.replaceChild(select, nameField);

    let logoBox = form.querySelector('.badge-award-logo');
    if (!logoBox) {
      logoBox = document.createElement('div');
      logoBox.className = 'badge-award-logo';
      logoBox.style.cssText = 'margin:4px 0 8px; min-height:50px;';
      select.parentNode.insertBefore(logoBox, select.nextSibling);
    }

    const updateLogo = () => {
      const val = select.value;
      if (val === '__custom__' || !val) {
        logoBox.innerHTML = '';
        return;
      }
      const def = state.badgeDefs.find(b => b.name === val);
      const awardLogoSrc = (def && def.logoUrl) || window.DEFAULT_BADGE_ICON || '';
      logoBox.innerHTML = awardLogoSrc
        ? `<img src="${escapeHtml(awardLogoSrc)}" onerror="this.onerror=null;this.src=window.DEFAULT_BADGE_ICON||'';" style="height:48px;max-width:80px;border-radius:6px;object-fit:contain;border:1px solid rgba(255,255,255,0.1);" />`
        : '';
    };

    select.addEventListener('change', () => {
      if (select.value === '__custom__') {
        const newInput = document.createElement('input');
        newInput.name = 'badgeName';
        newInput.placeholder = 'Badge Name';
        newInput.required = true;
        select.parentNode.replaceChild(newInput, select);
        if (logoBox) logoBox.innerHTML = '';
        setTimeout(enhanceBadgeAwardForm, 50);
      } else {
        updateLogo();
      }
    });

    updateLogo();
  } else {
    if (!nameField.dataset.hinted) {
      const hint = document.createElement('div');
      hint.style.cssText = 'font-size:11px;color:#5e6888;margin-top:2px;';
      hint.textContent = 'Tip: Add badge definitions in Configuration → Badges tab';
      nameField.parentNode.insertBefore(hint, nameField.nextSibling);
      nameField.dataset.hinted = '1';
    }
  }
}

function memberOptions(selected = '') {
  return '<option value="">Select Member</option>' +
    state.members.map(m => `<option value="${m.id}" ${selected === m.id ? 'selected' : ''}>${escapeHtml(m.fullName)}</option>`).join('');
}

function leaderOptions(selected = '') {
  return '<option value="">Select Leader</option>' +
    state.leaders.map(l => `<option value="${l.id}" ${selected === l.id ? 'selected' : ''}>${escapeHtml(l.fullName)}</option>`).join('');
}

function memberName(id) { return state.members.find(m => m.id === id)?.fullName || '—'; }
function leaderName(id) { return state.leaders.find(l => l.id === id)?.fullName || '—'; }
function leaderRole(id) { return state.leaders.find(l => l.id === id)?.role || 'No Rank'; }

function badgeDefByName(name) {
  return state.badgeDefs.find(b => (b.name || '').toLowerCase() === (name || '').toLowerCase());
}

function badgeDefLogo(nameOrId) {
  const def = typeof nameOrId === 'string'
    ? state.badgeDefs.find(b => b.name === nameOrId)
    : state.badgeDefs.find(b => b.id === nameOrId);
  // Always return an image: the badge-specific logo if it exists, otherwise
  // the default Lebanese-scout fleur-de-lis icon.
  return def?.logoUrl || window.DEFAULT_BADGE_ICON || null;
}

/* ======================================================================
   Units page
   ====================================================================== */

const UNIT_ORDER = ['Beavers', 'Cubs', 'Boyscouts', 'Girlscouts', 'Pioneers', 'Rovers', 'Leaders'];
const UNIT_ICONS = { Beavers: '🦫', Cubs: '🐾', Boyscouts: '⚜', Girlscouts: '🌸', Pioneers: '🏕', Rovers: '🧭', Leaders: '👔' };
let activeUnit = 'Beavers';

function renderUnitsPage() {
  const tabsEl = document.getElementById('unitsTabs');
  const contentEl = document.getElementById('unitsContent');
  if (!tabsEl || !contentEl) return;

  // Non-admin unit leaders only see their own unit.
  const visibleUnits = currentUser.isAdmin
    ? UNIT_ORDER
    : (currentUser.unit ? [currentUser.unit] : []);

  // Force active unit to something the user is allowed to see.
  if (!visibleUnits.includes(activeUnit)) {
    activeUnit = visibleUnits[0] || 'Beavers';
  }

  if (!visibleUnits.length) {
    tabsEl.innerHTML = '';
    contentEl.innerHTML = '<div class="panel"><div class="empty">You are not assigned to any unit.</div></div>';
    return;
  }

  tabsEl.innerHTML = visibleUnits.map(u => {
    const count = u === 'Leaders'
      ? state.leaders.length
      : state.members.filter(m => canonicalUnit(m.unit) === u).length;
    const active = u === activeUnit ? 'active' : '';
    return `<button type="button" class="unit-tab ${active}" data-unit="${u}">
              <span class="unit-tab-icon">${UNIT_ICONS[u] || '•'}</span>
              <span class="unit-tab-label">${u}</span>
              <span class="unit-tab-count">${count}</span>
            </button>`;
  }).join('');

  tabsEl.querySelectorAll('.unit-tab').forEach(btn => {
    btn.addEventListener('click', () => { activeUnit = btn.dataset.unit; renderUnitsPage(); });
  });

  if (activeUnit === 'Leaders') {
    const leaders = state.leaders.slice().sort((a, b) => (a.fullName || '').localeCompare(b.fullName || ''));
    const males = leaders.filter(l => l.gender === 'Male').length;
    const females = leaders.filter(l => l.gender === 'Female').length;

    const summary = `
      <div class="unit-summary">
        <div class="unit-summary-head">
          <div>
            <h2>👔 Leaders Overview</h2>
            <p class="muted">All registered adult group leaders and staff.</p>
          </div>
          <div class="unit-summary-stats">
            <div class="stat-pill"><span>Total Leaders</span><strong>${leaders.length}</strong></div>
            <div class="stat-pill"><span>Male</span><strong>${males}</strong></div>
            <div class="stat-pill"><span>Female</span><strong>${females}</strong></div>
          </div>
        </div>
      </div>
    `;

    let table;
    if (!leaders.length) {
      table = `<div class="panel"><div class="empty">No leaders registered yet.</div></div>`;
    } else {
      table = `
        <div class="panel">
          <div class="panel-header"><h3>Registered Leaders</h3></div>
          <div class="table-wrap">
            <table class="unit-members-table">
              <thead>
                <tr>
                  <th>Full Name</th><th>Gender</th><th>Role</th>
                  <th>Birth Date</th><th>Phone</th><th>Join Date</th><th>Email</th>
                </tr>
              </thead>
              <tbody>${leaders.map(unitLeaderRow).join('')}</tbody>
            </table>
          </div>
        </div>
      `;
    }

    contentEl.innerHTML = summary + table;

    contentEl.querySelectorAll('.leader-row').forEach(row => {
      row.addEventListener('click', () => {
        openLeaderProfile(row.dataset.id);
      });
    });
  } else {
    const members = state.members
      .filter(m => canonicalUnit(m.unit) === activeUnit)
      .slice()
      .sort((a, b) => (a.fullName || '').localeCompare(b.fullName || ''));

    const rule = UNIT_TRANSITIONS[activeUnit];
    const ages = members.map(m => ageDecimal(m.dob)).filter(a => a !== null);
    const avgAge = ages.length ? (ages.reduce((s, v) => s + v, 0) / ages.length) : 0;
    const males = members.filter(m => m.gender === 'Male').length;
    const females = members.filter(m => m.gender === 'Female').length;

    const summary = `
      <div class="unit-summary">
        <div class="unit-summary-head">
          <div>
            <h2>${UNIT_ICONS[activeUnit] || ''} ${escapeHtml(activeUnit)}</h2>
            <div class="muted">${rule
        ? `Moves to ${escapeHtml(rule.next)} at age ${rule.nextAge}`
        : 'No transition rule configured.'}</div>
          </div>
          <div class="unit-summary-stats">
            <div class="stat-pill"><span>Members</span><strong>${members.length}</strong></div>
            <div class="stat-pill"><span>Avg Age</span><strong>${ages.length ? avgAge.toFixed(2) : '—'}</strong></div>
            <div class="stat-pill"><span>Male</span><strong>${males}</strong></div>
            <div class="stat-pill"><span>Female</span><strong>${females}</strong></div>
          </div>
        </div>
      </div>
    `;

    let table;
    if (!members.length) {
      table = `<div class="panel"><div class="empty">No members in ${escapeHtml(activeUnit)} yet.</div></div>`;
    } else {
      table = `
        <div class="panel">
          <div class="panel-header"><h3>${escapeHtml(activeUnit)} Members</h3></div>
          <div class="table-wrap">
            <table class="unit-members-table">
              <thead>
                <tr>
                  <th>Full Name</th><th>Gender</th><th>Birth Date</th>
                  <th>Age</th><th>Time to Next Unit</th>
                  <th>Phone</th><th>Parent Type</th><th>Parents Phone</th>
                  <th>Blood</th><th>Nationality</th><th>Email</th>
                </tr>
              </thead>
              <tbody>${members.map(unitMemberRow).join('')}</tbody>
            </table>
          </div>
        </div>
      `;
    }

    contentEl.innerHTML = summary + table;

    contentEl.querySelectorAll('.member-row').forEach(row => {
      row.addEventListener('click', () => {
        openMemberProfile(row.dataset.id);
      });
    });
  }
}

function unitMemberRow(m) {
  const age = ageDecimal(m.dob);
  const next = timeUntilNextUnit(m);

  let nextCell;
  if (!next) {
    nextCell = '<span class="muted">—</span>';
  } else if (next.passed) {
    nextCell = `<span class="next-eligible">Eligible now → ${escapeHtml(next.nextUnit || '—')}</span>`;
  } else {
    const urgencyClass =
      next.days <= 30 ? 'next-critical' :
        next.days <= 180 ? 'next-warning' : 'next-info';
    nextCell = `
      <div class="next-cell ${urgencyClass}">
        <strong>${escapeHtml(next.text)}</strong>
        <span class="muted">→ ${escapeHtml(next.nextUnit || '—')}</span>
      </div>
    `;
  }

  return `
    <tr class="member-row" data-id="${m.id}" style="cursor: pointer;">
      <td><strong>${escapeHtml(m.fullName || '—')}</strong></td>
      <td>${escapeHtml(m.gender || '—')}</td>
      <td>${escapeHtml(m.dob || '—')}</td>
      <td>${age !== null ? age.toFixed(2) : '—'}</td>
      <td>${nextCell}</td>
      <td>${escapeHtml(m.phone || '—')}</td>
      <td>${escapeHtml(m.parentType || '—')}</td>
      <td>${escapeHtml(m.parentPhone || '—')}</td>
      <td>${escapeHtml(m.bloodType || '—')}</td>
      <td>${escapeHtml(m.nationality || '—')}</td>
      <td>${escapeHtml(m.email || '—')}</td>
    </tr>
  `;
}

function unitLeaderRow(l) {
  return `
    <tr class="leader-row" data-id="${l.id}" style="cursor: pointer;">
      <td><strong>${escapeHtml(l.fullName || '—')}</strong></td>
      <td>${escapeHtml(l.gender || '—')}</td>
      <td>${escapeHtml(l.role || '—')}</td>
      <td>${escapeHtml(l.dob || '—')}</td>
      <td>${escapeHtml(l.phone || '—')}</td>
      <td>${escapeHtml(l.joinDate || '—')}</td>
      <td>${escapeHtml(l.email || '—')}</td>
    </tr>
  `;
}

async function openMemberProfile(memberId) {
  const m = await ensureMemberDetail(memberId);
  if (!m) {
    showToast('Member not found', 'error');
    return;
  }

  const nameEl = $('#profileMemberName'); if (nameEl) nameEl.textContent = m.fullName || 'Member Profile';
  const unitEl = $('#profileMemberUnit'); if (unitEl) unitEl.textContent = m.unit || '—';

  const fnEl = $('#profileFullName'); if (fnEl) fnEl.textContent = m.fullName || '—';
  const gEl = $('#profileGender'); if (gEl) gEl.textContent = m.gender || '—';
  const dobEl = $('#profileDob'); if (dobEl) dobEl.textContent = m.dob || '—';

  const age = ageDecimal(m.dob);
  const ageEl = $('#profileAge'); if (ageEl) ageEl.textContent = age !== null ? age.toFixed(2) : '—';

  const pEl = $('#profilePhone'); if (pEl) pEl.textContent = m.phone || '—';
  const ptEl = $('#profileParentType'); if (ptEl) ptEl.textContent = m.parentType || '—';
  const ppEl = $('#profileParentPhone'); if (ppEl) ppEl.textContent = m.parentPhone || '—';
  const btEl = $('#profileBloodType'); if (btEl) btEl.textContent = m.bloodType || '—';
  const natEl = $('#profileNationality'); if (natEl) natEl.textContent = m.nationality || '—';
  const emEl = $('#profileEmail'); if (emEl) emEl.textContent = m.email || '—';

  const dlBtn = $('#downloadProfilePdfBtn');
  if (dlBtn) dlBtn.dataset.memberId = memberId;

  const badgesContainer = $('#profileBadgesContainer');
  if (badgesContainer) {
    const badges = state.badges.filter(b => b.memberId === memberId);
    if (!badges.length) {
      badgesContainer.innerHTML = `
        <div class="empty-placeholder" style="grid-column: 1 / -1; padding: 24px 16px;">
          <div class="placeholder-icon">🏅</div>
          <h4>No badges earned yet</h4>
          <p class="muted">This member has not been awarded any badges yet.</p>
        </div>
      `;
    } else {
      badgesContainer.innerHTML = badges.map(b => {
        const logo = badgeDefLogo(b.badgeName);
        const logoImg = logo
          ? `<img src="${escapeHtml(logo)}" alt="${escapeHtml(b.badgeName)}" onerror="this.onerror=null;this.src=window.DEFAULT_BADGE_ICON||'';" />`
          : `<div class="fallback-icon">🏅</div>`; // badgeDefLogo now always returns the default icon
        return `
          <div class="profile-badge-item">
            ${logoImg}
            <div class="badge-name">${escapeHtml(b.badgeName)}</div>
            <div class="badge-date">${escapeHtml(b.awardedDate || '—')}</div>
          </div>
        `;
      }).join('');
    }
  }

  const milestonesContainer = $('#profileMilestonesContainer');
  if (milestonesContainer) {
    const ranks = state.ranks.filter(r => r.memberId === memberId);
    if (!ranks.length) {
      milestonesContainer.innerHTML = `
        <div class="empty-placeholder" style="padding: 24px 16px;">
          <div class="placeholder-icon">🧭</div>
          <h4>No milestones recorded yet</h4>
          <p class="muted">No rank milestones or updates are recorded for this scout yet.</p>
        </div>
      `;
    } else {
      milestonesContainer.innerHTML = ranks.map(r => `
        <div class="profile-milestone-item">
          <div class="profile-milestone-title">${escapeHtml(r.rankName)}</div>
          <div class="profile-milestone-date">Effective: ${escapeHtml(r.effectiveDate)}</div>
          ${r.notes ? `<div class="profile-milestone-notes">Notes: ${escapeHtml(r.notes)}</div>` : ''}
        </div>
      `).join('');
    }
  }

  switchView('memberProfile');
}

