const CHART_PALETTE = [
  '#6366f1', '#10b981', '#f59e0b', '#ef4444', '#3b82f6',
  '#a855f7', '#ec4899', '#14b8a6', '#f97316', '#84cc16',
  '#0ea5e9', '#8b5cf6'
];

function drawOrUpdateChart(key, canvasId, config) {
  if (typeof Chart === 'undefined') return;
  const canvas = document.getElementById(canvasId);
  if (!canvas) return;
  // Destroy previous instance so we can redraw fresh
  if (charts[key]) {
    try { charts[key].destroy(); } catch (_) {}
    charts[key] = null;
  }
  charts[key] = new Chart(canvas.getContext('2d'), config);
}

function renderStatisticsPage() {
  // Non-admin with no assigned unit: skip charts entirely (empty state handles it).
  if (!currentUser.isAdmin && !currentUser.unit) return;

  const members = scopedMembers();
  const total = members.length;

  // Hide the "Members by Unit" chart for unit leaders (only one unit — meaningless).
  const unitChartCard = document.getElementById('unitChart')?.closest('.chart-card');
  if (unitChartCard) unitChartCard.style.display = currentUser.isAdmin ? '' : 'none';

  // ---- Text stat cards ----
  const setText = (id, val) => { const el = $('#' + id); if (el) el.textContent = val; };
  setText('statsTotalMembers', total);

  let avgAge = 0;
  const ages = members.map(m => ageDecimal(m.dob)).filter(a => a !== null);
  if (ages.length) avgAge = (ages.reduce((s, v) => s + v, 0) / ages.length).toFixed(1);
  setText('statsAvgAge', total > 0 && avgAge > 0 ? avgAge : '—');

  const bloodCounts = {};
  members.forEach(m => {
    if (m.bloodType) {
      const bt = String(m.bloodType).toUpperCase().trim();
      bloodCounts[bt] = (bloodCounts[bt] || 0) + 1;
    }
  });
  let commonBlood = '—', maxBlood = 0;
  Object.entries(bloodCounts).forEach(([bt, c]) => {
    if (c > maxBlood) { maxBlood = c; commonBlood = bt; }
  });
  setText('statsCommonBlood', commonBlood);

  const nationalityCounts = {};
  members.forEach(m => {
    const n = (m.nationality || '').trim();
    if (n) nationalityCounts[n] = (nationalityCounts[n] || 0) + 1;
  });
  setText('statsNationalities', Object.keys(nationalityCounts).length);

  if (typeof Chart === 'undefined') return;

  // ---- 1) Members by Unit (bar) — admin only ----
  const unitOrder = ['Beavers', 'Cubs', 'Boyscouts', 'Girlscouts', 'Pioneers', 'Rovers'];
  const unitCounts = unitOrder.map(u =>
    members.filter(m => canonicalUnit(m.unit) === u).length
  );
  if (currentUser.isAdmin) drawOrUpdateChart('unit', 'unitChart', {
    type: 'bar',
    data: {
      labels: unitOrder,
      datasets: [{
        label: 'Members',
        data: unitCounts,
        backgroundColor: CHART_PALETTE.slice(0, unitOrder.length),
        borderRadius: 6,
        borderSkipped: false
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: { legend: { display: false } },
      scales: {
        y: { beginAtZero: true, ticks: { precision: 0 } }
      }
    }
  });

  // ---- 2) Age Distribution (bar, buckets) ----
  const buckets = [
    { label: '0-6',   min: 0,  max: 6  },
    { label: '7-10',  min: 7,  max: 10 },
    { label: '11-14', min: 11, max: 14 },
    { label: '15-17', min: 15, max: 17 },
    { label: '18-21', min: 18, max: 21 },
    { label: '22+',   min: 22, max: 200 }
  ];
  const ageBucketCounts = buckets.map(b =>
    ages.filter(a => a >= b.min && a <= b.max).length
  );
  drawOrUpdateChart('age', 'ageChart', {
    type: 'bar',
    data: {
      labels: buckets.map(b => b.label),
      datasets: [{
        label: 'Members',
        data: ageBucketCounts,
        backgroundColor: '#10b981',
        borderRadius: 6,
        borderSkipped: false
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: { legend: { display: false } },
      scales: { y: { beginAtZero: true, ticks: { precision: 0 } } }
    }
  });

  // ---- 3) Blood Type Distribution (doughnut) ----
  const bloodLabels = Object.keys(bloodCounts);
  const bloodValues = bloodLabels.map(l => bloodCounts[l]);
  drawOrUpdateChart('blood', 'bloodChart', {
    type: 'doughnut',
    data: {
      labels: bloodLabels.length ? bloodLabels : ['No data'],
      datasets: [{
        data: bloodValues.length ? bloodValues : [1],
        backgroundColor: bloodLabels.length ? CHART_PALETTE : ['#e5e7eb'],
        borderWidth: 2,
        borderColor: '#fff'
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      cutout: '60%',
      plugins: { legend: { position: 'bottom' } }
    }
  });

  // ---- 4) Top Nationalities (horizontal bar, top 6) ----
  const natSorted = Object.entries(nationalityCounts)
    .sort((a, b) => b[1] - a[1]).slice(0, 6);
  drawOrUpdateChart('nationality', 'nationalityChart', {
    type: 'bar',
    data: {
      labels: natSorted.length ? natSorted.map(x => x[0]) : ['No data'],
      datasets: [{
        label: 'Members',
        data: natSorted.length ? natSorted.map(x => x[1]) : [0],
        backgroundColor: '#3b82f6',
        borderRadius: 6,
        borderSkipped: false
      }]
    },
    options: {
      indexAxis: 'y',
      responsive: true,
      maintainAspectRatio: false,
      plugins: { legend: { display: false } },
      scales: { x: { beginAtZero: true, ticks: { precision: 0 } } }
    }
  });

  // ---- 5) Top 5 Common Names (bar) ----
  const nameCounts = {};
  members.forEach(m => {
    const n = (m.firstName || '').trim();
    if (n) nameCounts[n] = (nameCounts[n] || 0) + 1;
  });
  const nameSorted = Object.entries(nameCounts)
    .sort((a, b) => b[1] - a[1]).slice(0, 5);
  drawOrUpdateChart('names', 'namesChart', {
    type: 'bar',
    data: {
      labels: nameSorted.length ? nameSorted.map(x => x[0]) : ['No data'],
      datasets: [{
        label: 'Members',
        data: nameSorted.length ? nameSorted.map(x => x[1]) : [0],
        backgroundColor: '#a855f7',
        borderRadius: 6,
        borderSkipped: false
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: { legend: { display: false } },
      scales: { y: { beginAtZero: true, ticks: { precision: 0 } } }
    }
  });
}

