async function handleBadgeDefSubmit(e) {
  e.preventDefault();
  const form = e.target;
  const d = formToObject(form);

  let logoUrl = d.logoUrl ? d.logoUrl.trim() : '';

  const logoFileInput = $('#badgeLogoFile');
  if (logoFileInput && logoFileInput.dataset.previewData) {
    logoUrl = logoFileInput.dataset.previewData;
  }

  if (!d.badgeName || !d.badgeName.trim()) {
    return alert('Badge name is required.');
  }

  const payload = {
    name: d.badgeName.trim(),
    category: d.category || 'أخرى',
    logo_url: logoUrl || null
  };

  const { data, error } = await supabaseClient.from('badge_definitions').insert(payload).select().single();
  if (error) return alert(error.message);

  state.badgeDefs.push(mapBadgeDef(data));
  form.reset();
  if (logoFileInput) {
    logoFileInput.value = '';
    delete logoFileInput.dataset.previewData;
  }
  const preview = $('#badgeLogoPreview');
  if (preview) preview.innerHTML = '';
  renderBadgeDefs();
}

async function deleteBadgeDef(id) {
  if (!confirm('Delete this badge definition?')) return;
  const { error } = await supabaseClient.from('badge_definitions').delete().eq('id', id);
  if (error) return alert(error.message);
  state.badgeDefs = state.badgeDefs.filter(b => b.id !== id);
  renderBadgeDefs();
}

function renderBadgeDefs() {
  const tbody = $('#badgeDefsTable');
  if (!tbody) return;

  if (!state.badgeDefs.length) {
    tbody.innerHTML = '<tr><td colspan="4" class="muted">No badge definitions yet.</td></tr>';
    return;
  }

  tbody.innerHTML = state.badgeDefs.map(b => {
    const logoSrc = b.logoUrl || window.DEFAULT_BADGE_ICON || '';
    const logo = logoSrc
      ? `<img src="${escapeHtml(logoSrc)}" onerror="this.onerror=null;this.src=window.DEFAULT_BADGE_ICON||'';" style="height:42px; width:auto; max-width:70px; border-radius:6px; object-fit:contain;" />`
      : `<div style="width:42px;height:42px;background:#f3f4f6;border-radius:6px;"></div>`;

    return `
      <tr>
        <td>${logo}</td>
        <td><strong>${escapeHtml(b.name)}</strong></td>
        <td>${escapeHtml(b.category)}</td>
        <td><button onclick="deleteBadgeDef('${b.id}')">Delete</button></td>
      </tr>
    `;
  }).join('');
}

