let selectedPersonId = null;
let selectedPersonType = null;
let assignBadgesActiveFilter = 'All';
let assignBadgesSearchQuery = '';
let selectedBadgeNames = new Set();

function bindAssignBadgesControls() {
  // Search input
  const searchInput = $('#assignBadgesSearchInput');
  if (searchInput && !searchInput.dataset.bound) {
    searchInput.dataset.bound = '1';
    searchInput.addEventListener('input', e => {
      assignBadgesSearchQuery = (e.target.value || '').trim().toLowerCase();
      renderAssignBadgesPeopleList();
    });
  }

  // Unit filter pills
  const filters = document.querySelectorAll('#assignBadgesUnitFilters .filter-pill');
  filters.forEach(btn => {
    if (btn.dataset.bound) return;
    btn.dataset.bound = '1';
    btn.addEventListener('click', () => {
      filters.forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      assignBadgesActiveFilter = btn.dataset.unit || 'All';
      renderAssignBadgesPeopleList();
    });
  });
}

function renderAssignBadgesPeopleList() {
  const listEl = $('#assignBadgesPeopleList');
  if (!listEl) return;

  // Hide unit filter pills that this user isn't allowed to see.
  document.querySelectorAll('#assignBadgesUnitFilters .filter-pill').forEach(btn => {
    const u = btn.dataset.unit;
    let allowed = true;
    if (!currentUser.isAdmin) {
      // Unit leaders can only see their own unit; hide "All" and other units and "Leaders".
      allowed = (u === currentUser.unit);
    }
    btn.style.display = allowed ? '' : 'none';
  });
  if (!currentUser.isAdmin && currentUser.unit) {
    assignBadgesActiveFilter = currentUser.unit;
  }

  // Build a unified pool of people (members + leaders)
  const membersSource = currentUser.isAdmin ? (state.members || []) : scopedMembers();
  const members = membersSource.map(m => ({
    id: m.id,
    type: 'member',
    fullName: m.fullName || [m.firstName, m.middleName, m.lastName].filter(Boolean).join(' '),
    unit: canonicalUnit(m.unit) || m.unit || '—'
  }));
  const leaders = currentUser.isAdmin
    ? (state.leaders || []).map(l => ({
        id: l.id,
        type: 'leader',
        fullName: l.fullName || [l.firstName, l.middleName, l.lastName].filter(Boolean).join(' '),
        unit: 'Leaders'
      }))
    : [];

  let people = members.concat(leaders);

  // Unit filter
  if (assignBadgesActiveFilter && assignBadgesActiveFilter !== 'All') {
    if (assignBadgesActiveFilter === 'Leaders') {
      people = people.filter(p => p.type === 'leader');
    } else {
      people = people.filter(p => p.type === 'member' && p.unit === assignBadgesActiveFilter);
    }
  }

  // Search filter
  if (assignBadgesSearchQuery) {
    people = people.filter(p => (p.fullName || '').toLowerCase().includes(assignBadgesSearchQuery));
  }

  // Sort by name
  people.sort((a, b) => (a.fullName || '').localeCompare(b.fullName || ''));

  if (!people.length) {
    const total = state.members.length + state.leaders.length;
    const msg = total === 0
      ? 'No members or leaders found. Add some in the Members / Leaders tabs first.'
      : 'No matches for the current filter/search.';
    listEl.innerHTML = `<div class="muted" style="padding:14px; text-align:center; font-size:13px;">${msg}</div>`;
    return;
  }

  listEl.innerHTML = people.map(p => {
    const isSelected = (selectedPersonId === p.id && selectedPersonType === p.type);
    return `
      <div class="person-select-item ${isSelected ? 'selected' : ''}"
           data-person-id="${escapeHtml(p.id)}"
           data-person-type="${p.type}">
        <span>${escapeHtml(p.fullName || 'Unnamed')}</span>
        <span class="person-badge-pill">${escapeHtml(p.unit)}</span>
      </div>
    `;
  }).join('');

  // Bind click handlers
  listEl.querySelectorAll('.person-select-item').forEach(row => {
    row.addEventListener('click', () => {
      selectedPersonId = row.dataset.personId;
      selectedPersonType = row.dataset.personType;
      // Reset selection highlight
      listEl.querySelectorAll('.person-select-item').forEach(r => r.classList.remove('selected'));
      row.classList.add('selected');
      loadSelectedPersonBadges();
    });
  });
}

function loadSelectedPersonBadges() {
  const container = $('#assignBadgesListContainer');
  const grid = $('#badgesGrid');
  const countEl = $('#selectedBadgesCount');
  if (!container || !grid) return;

  if (!selectedPersonId || !selectedPersonType) {
    container.style.display = 'none';
    return;
  }

  container.style.display = '';

  // Which badges does this person already have?
  const existing = selectedPersonType === 'leader'
    ? (state.leaderBadges || []).filter(b => b.leaderId === selectedPersonId).map(b => b.badgeName)
    : (state.badges || []).filter(b => b.memberId === selectedPersonId).map(b => b.badgeName);
  const existingSet = new Set(existing);

  // Reset selection to reflect what person currently has
  selectedBadgeNames = new Set(existing);

  const defs = state.badgeDefs || [];
  if (!defs.length) {
    grid.innerHTML = '<div class="muted" style="padding:14px; grid-column:1/-1; text-align:center;">No badge definitions available. Add some in the "Badge Definitions" tab first.</div>';
    if (countEl) countEl.textContent = `${selectedBadgeNames.size} selected`;
    return;
  }

  grid.innerHTML = defs.map(b => {
    const checked = selectedBadgeNames.has(b.name);
    const already = existingSet.has(b.name);
    const logoSrc = b.logoUrl || window.DEFAULT_BADGE_ICON || '';
    const logo = logoSrc
      ? `<img src="${escapeHtml(logoSrc)}" alt="" draggable="false" onerror="this.onerror=null;this.src=window.DEFAULT_BADGE_ICON||'';" style="height:44px;width:44px;object-fit:contain;border-radius:6px;pointer-events:none;" />`
      : `<div style="height:44px;width:44px;background:#f3f4f6;border-radius:6px;pointer-events:none;"></div>`;
    // Use a plain <div> (not <label>+<input>) to avoid the checkbox getting
    // focus on click, which was causing the scrollable grid to auto-scroll
    // and produce a "vibration" effect.
    return `
      <div class="badge-select-card ${checked ? 'selected' : ''}"
           data-badge-name="${escapeHtml(b.name)}"
           style="display:flex; flex-direction:column; align-items:center; gap:6px; padding:10px; border:1px solid var(--line); border-radius:var(--radius-sm); cursor:pointer; background:${checked ? 'rgba(99,102,241,0.08)' : 'var(--panel-solid)'}; text-align:center; user-select:none; -webkit-user-select:none; position:relative;">
        <span aria-hidden="true" class="badge-tick" style="position:absolute; top:6px; right:6px; width:16px; height:16px; border-radius:4px; border:1px solid var(--line-strong); background:${checked ? 'var(--primary)' : '#fff'}; color:#fff; font-size:11px; line-height:14px; text-align:center; font-weight:700;">${checked ? '✓' : ''}</span>
        ${logo}
        <span style="font-size:12px; font-weight:600; color:var(--text); pointer-events:none;">${escapeHtml(b.name)}</span>
        ${already ? '<span class="muted" style="font-size:10px; pointer-events:none;">Owned</span>' : ''}
      </div>
    `;
  }).join('');

  if (countEl) countEl.textContent = `${selectedBadgeNames.size} selected`;

  grid.querySelectorAll('.badge-select-card').forEach(card => {
    card.addEventListener('click', e => {
      // Don't let the browser scroll the grid to bring anything into view
      e.preventDefault();
      const name = card.dataset.badgeName;
      if (!name) return;
      const nowChecked = !selectedBadgeNames.has(name);
      if (nowChecked) selectedBadgeNames.add(name);
      else selectedBadgeNames.delete(name);

      card.classList.toggle('selected', nowChecked);
      card.style.background = nowChecked ? 'rgba(99,102,241,0.08)' : 'var(--panel-solid)';
      const tick = card.querySelector('.badge-tick');
      if (tick) {
        tick.textContent = nowChecked ? '✓' : '';
        tick.style.background = nowChecked ? 'var(--primary)' : '#fff';
      }
      if (countEl) countEl.textContent = `${selectedBadgeNames.size} selected`;
    });
  });
}

async function handleApplyBadges() {
  if (!selectedPersonId || !selectedPersonType) {
    return showToast('Select a person first', 'warning');
  }
  if (!supabaseClient) {
    return showToast('Not connected to database', 'error');
  }

  const isLeader = selectedPersonType === 'leader';
  const table = isLeader ? 'leader_badges' : 'badges';
  const idField = isLeader ? 'leader_id' : 'member_id';

  const currentList = isLeader
    ? (state.leaderBadges || []).filter(b => b.leaderId === selectedPersonId)
    : (state.badges || []).filter(b => b.memberId === selectedPersonId);
  const currentSet = new Set(currentList.map(b => b.badgeName));

  const desired = selectedBadgeNames;

  const toAdd = [...desired].filter(n => !currentSet.has(n));
  const toRemove = currentList.filter(b => !desired.has(b.badgeName));

  try {
    // Insert new badges
    if (toAdd.length) {
      const rows = toAdd.map(name => ({
        [idField]: selectedPersonId,
        badge_name: name,
        awarded_date: new Date().toISOString().slice(0, 10)
      }));
      const { data, error } = await supabaseClient.from(table).insert(rows).select();
      if (error) throw error;
      const mapped = (data || []).map(isLeader ? mapLeaderBadge : mapBadge);
      if (isLeader) state.leaderBadges.push(...mapped);
      else state.badges.push(...mapped);
    }

    // Delete removed badges
    if (toRemove.length) {
      const ids = toRemove.map(b => b.id);
      const { error } = await supabaseClient.from(table).delete().in('id', ids);
      if (error) throw error;
      if (isLeader) {
        state.leaderBadges = state.leaderBadges.filter(b => !ids.includes(b.id));
      } else {
        state.badges = state.badges.filter(b => !ids.includes(b.id));
      }
    }

    showToast(`Updated: +${toAdd.length} / -${toRemove.length}`, 'success');
    renderAll();
    loadSelectedPersonBadges();
  } catch (err) {
    console.error(err);
    showToast(err.message || 'Failed to update badges', 'error');
  }
}

async function openLeaderProfile(leaderId) {
  const l = await ensureLeaderDetail(leaderId);
  if (!l) {
    showToast('Leader not found', 'error');
    return;
  }

  const nameEl = $('#profileLeaderName');
  if (nameEl) nameEl.textContent = l.fullName || 'Leader Profile';

  switchView('leaderProfile');
}

/* ======================================================================
   Helpers
   ====================================================================== */

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;').replace(/'/g, '&#39;');
}

function formatLongDate(date) {
  if (!date) return '—';
  const d = new Date(date);
  if (isNaN(d)) return '—';
  return d.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
}

function formatTimeRange(start, end) {
  return [start, end].filter(Boolean).join(' - ') || 'No time';
}

